/**
 * Dashboard Page
 *
 * Root page wrapper that renders the main dashboard with financial metrics,
 * charts, and key performance indicators. Handles authentication via ProtectedRoute,
 * maintenance mode checks, and error boundary wrapping.
 */

import DashboardPageContent from '@/components/CMS/dashboard/DashboardPageContent';
import ProtectedRoute from '@/components/shared/auth/ProtectedRoute';
import MaintenanceWrapper from '@/components/shared/maintenance/MaintenanceWrapper';
import PageErrorBoundary from '@/components/shared/ui/errors/PageErrorBoundary';
export default function DashboardPage() {
  return (
    <ProtectedRoute requiredPage="dashboard">
      <MaintenanceWrapper pageKey="dashboard">
        <PageErrorBoundary>
          <DashboardPageContent />
        </PageErrorBoundary>
      </MaintenanceWrapper>
    </ProtectedRoute>
  );
}

'use client';

import { Suspense } from 'react';

// Components
import ReportsPageContent from '@/components/CMS/reports/ReportsPageContent';
import { ReportsPageSkeleton } from '@/components/shared/ui/skeletons/ReportsSkeletons';
import ProtectedRoute from '@/components/shared/auth/ProtectedRoute';
import MaintenanceWrapper from '@/components/shared/maintenance/MaintenanceWrapper';

/**
 * Reports Page
 * Main entry point for the reports section with comprehensive analytics and reporting
 *
 * Features:
 * - Multi-tab interface (Locations, Machines, Meters)
 * - Role-based access control and permissions
 * - Real-time data updates and filtering
 * - Responsive design for desktop and mobile
 * - Advanced filtering and export capabilities
 * - Currency conversion for Admin/Developer viewing "All Licencees"
 */
export default function ReportsPage() {
  return (
    <ProtectedRoute requiredPage="reports">
      <MaintenanceWrapper pageKey="reports">
        <Suspense fallback={<ReportsPageSkeleton />}>
          <ReportsPageContent />
        </Suspense>
      </MaintenanceWrapper>
    </ProtectedRoute>
  );
}

