1	/**
2	 * Reviewer Scale Utility
3	 *
4	 * Centralises the reviewer multiplier calculation used across collection report APIs.
5	 * Reviewers see a scaled-down view of all financial data based on their multiplier.
6	 *
7	 * Formula:  scale = 1 - multiplier   (e.g. multiplier 0.30 → scale 0.70)
8	 * Non-reviewers always receive scale = 1 (no transformation).
9	 *
10	 * @module app/api/lib/utils/reviewerScale
11	 */
12	
13	// Minimal shape needed — avoids coupling to a specific JWT/DB type.
14	type UserForScale = {
15	  moneyInMultiplier?: number | null;
16	  moneyOutAndJackpotMultiplier?: number | null;
17	  reviewerMultiplierStartTime?: Date | string | null;
18	  roles?: string[] | unknown[];
19	};
20	
21	// ============================================================================
22	// Scale factors for dual multiplier system
23	// ============================================================================
24	
25	export const DEFAULT_REVIEWER_MULTIPLIER_START_DATE = '2026-04-01';
26	
27	const DEFAULT_REVIEWER_MULTIPLIER_START_TIMESTAMP = new Date(
28	  `${DEFAULT_REVIEWER_MULTIPLIER_START_DATE}T00:00:00.000Z`
29	).getTime();
30	
31	function parseTimestamp(
32	  value: Date | string | null | undefined
33	): number | null {
34	  if (!value) {
35	    return null;
36	  }
37	
38	  if (value instanceof Date) {
39	    const dateTimestamp = value.getTime();
40	    return Number.isNaN(dateTimestamp) ? null : dateTimestamp;
41	  }
42	
43	  if (typeof value === 'string') {
44	    const parsedTimestamp = new Date(value).getTime();
45	    return Number.isNaN(parsedTimestamp) ? null : parsedTimestamp;
46	  }
47	
48	  return null;
49	}
50	
51	function resolveReferenceTimestamp(
52	  referenceDate?: Date | string | null
53	): number {
54	  const parsedReferenceTimestamp = parseTimestamp(referenceDate);
55	  return parsedReferenceTimestamp ?? Date.now();
56	}
57	
58	export function shouldApplyReviewerMultipliers(
59	  user: UserForScale,
60	  referenceDate?: Date | string | null
61	): boolean {
62	  if (!user || typeof user !== 'object') {
63	    return false;
64	  }
65	
66	  const isReviewer = (user.roles as string[])?.includes('reviewer') ?? false;
67	  if (!isReviewer) {
68	    return false;
69	  }
70	
71	  const configuredStartTimestamp =
72	    parseTimestamp(user.reviewerMultiplierStartTime) ??
73	    DEFAULT_REVIEWER_MULTIPLIER_START_TIMESTAMP;
74	  const dataTimestamp = resolveReferenceTimestamp(referenceDate);
75	  return dataTimestamp >= configuredStartTimestamp;
76	}
77	
78	/**
79	 * Computes the money-in view scale factor for the given user.
80	 *
81	 * Returns `1 - moneyInMultiplier` for reviewer-role users with a non-zero multiplier,
82	 * or `1` for everyone else.
83	 *
84	 * @example
85	 * getMoneyInScale({ roles: ['reviewer'], moneyInMultiplier: 0.3 }) // → 0.7
86	 * getMoneyInScale({ roles: ['admin'],    moneyInMultiplier: 0.3 }) // → 1
87	 * getMoneyInScale({ roles: ['reviewer'], moneyInMultiplier: 0   }) // → 1
88	 */
89	export function getMoneyInScale(
90	  user: UserForScale,
91	  referenceDate?: Date | string | null
92	): number {
93	  if (!user || typeof user !== 'object') {
94	    console.error('[getMoneyInScale] user is required and must be an object');
95	    return 1;
96	  }
97	
98	  const multiplier = user.moneyInMultiplier ?? 0;
99	  return shouldApplyReviewerMultipliers(user, referenceDate) && multiplier
100	    ? 1 - multiplier
101	    : 1;
102	}
103	
104	/**
105	 * Computes the money-out & jackpot view scale factor for the given user.
106	 *
107	 * Returns `1 - moneyOutAndJackpotMultiplier` for reviewer-role users with a non-zero multiplier,
108	 * or `1` for everyone else.
109	 *
110	 * @example
111	 * getMoneyOutAndJackpotScale({ roles: ['reviewer'], moneyOutAndJackpotMultiplier: 0.5 }) // → 0.5
112	 * getMoneyOutAndJackpotScale({ roles: ['admin'],    moneyOutAndJackpotMultiplier: 0.5 }) // → 1
113	 * getMoneyOutAndJackpotScale({ roles: ['reviewer'], moneyOutAndJackpotMultiplier: 0   }) // → 1
114	 */
115	export function getMoneyOutAndJackpotScale(
116	  user: UserForScale,
117	  referenceDate?: Date | string | null
118	): number {
119	  if (!user || typeof user !== 'object') {
120	    console.error(
121	      '[getMoneyOutAndJackpotScale] user is required and must be an object'
122	    );
123	    return 1;
124	  }
125	
126	  const multiplier = user.moneyOutAndJackpotMultiplier ?? 0;
127	  return shouldApplyReviewerMultipliers(user, referenceDate) && multiplier
128	    ? 1 - multiplier
129	    : 1;
130	}
131	
132	/**
133	 * @deprecated Use getMoneyInScale() and getMoneyOutAndJackpotScale() instead.
134	 *
135	 * Kept for backward compatibility. Defaults to money-in scale behavior.
136	 */
137	export function getReviewerScale(
138	  user: UserForScale,
139	  referenceDate?: Date | string | null
140	): number {
141	  return getMoneyInScale(user, referenceDate);
142	}
143	
144	// ============================================================================
145	// Per-machine financial values
146	// ============================================================================
147	
148	export type MachineValuesInput = {
149	  /** Coins/bills in  — prevIn */
150	  drop: number;
151	  /** Coins/bills out — prevOut */
152	  cancelled: number;
153	  /** movement.gross from the collection document */
154	  meterGross: number;
155	  jackpot: number;
156	  /** meterGross - jackpot */
157	  netGross: number;
158	  /**
159	   * Raw SAS gross for the display column (meterData.drop - meterData.cancelled).
160	   * This is the pre-jackpot-adjustment value. When hasNoSasData is true this
161	   * field is irrelevant — the output will be 0.
162	   */
163	  sasGross: number;
164	  /** meterGross − adjustedSasGross (already computed in the caller) */
165	  variation: number;
166	  /** True when no SAS time window exists or no meter records were found */
167	  hasNoSasData: boolean;
168	};
169	
170	export type MachineValuesScaled = {
171	  drop: number;
172	  cancelled: number;
173	  meterGross: number;
174	  jackpot: number;
175	  netGross: number;
176	  /** 0 when hasNoSasData is true, scaled sasGross otherwise */
177	  sasGross: number;
178	  variation: number;
179	};
180	
181	/**
182	 * Applies the reviewer scale factors to all per-machine financial values in one call.
183	 *
184	 * Scales money-in values (drop, meterGross) with moneyInScale.
185	 * Scales money-out and jackpot values (cancelled, jackpot) with moneyOutScale.
186	 * NetGross is recalculated from scaled components.
187	 * Variation uses moneyInScale.
188	 *
189	 * When `hasNoSasData` is true the output `sasGross` is forced to `0` regardless of scale.
190	 */
191	export function scaleMachineValues(
192	  values: MachineValuesInput,
193	  moneyInScale: number,
194	  moneyOutScale: number
195	): MachineValuesScaled {
196	  if (
197	    !values ||
198	    typeof values !== 'object' ||
199	    typeof moneyInScale !== 'number' ||
200	    typeof moneyOutScale !== 'number'
201	  ) {
202	    console.error(
203	      '[scaleMachineValues] values (object), moneyInScale (number), and moneyOutScale (number) are required'
204	    );
205	    return {
206	      drop: 0,
207	      cancelled: 0,
208	      meterGross: 0,
209	      jackpot: 0,
210	      netGross: 0,
211	      sasGross: 0,
212	      variation: 0,
213	    };
214	  }
215	
216	  const {
217	    drop,
218	    cancelled,
219	    meterGross,
220	    jackpot,
221	    sasGross,
222	    variation,
223	    hasNoSasData,
224	  } = values;
225	
226	  const scaledDrop = Math.round(drop * moneyInScale * 100) / 100;
227	  const scaledCancelled = Math.round(cancelled * moneyOutScale * 100) / 100;
228	  const scaledMeterGross = Math.round(meterGross * moneyInScale * 100) / 100;
229	  const scaledJackpot = Math.round(jackpot * moneyOutScale * 100) / 100;
230	
231	  return {
232	    drop: scaledDrop,
233	    cancelled: scaledCancelled,
234	    meterGross: scaledMeterGross,
235	    jackpot: scaledJackpot,
236	    netGross: Math.round((scaledMeterGross - scaledJackpot) * 100) / 100,
237	    sasGross: hasNoSasData ? 0 : Math.round(sasGross * moneyInScale * 100) / 100,
238	    variation: Math.round(variation * moneyInScale * 100) / 100,
239	  };
240	}
241	
242	// ============================================================================
243	// Report-level summary fields  (used by the collection-reports list API)
244	// ============================================================================
245	
246	export type ReportFinancials = {
247	  amountCollected?: number | null;
248	  amountToCollect?: number | null;
249	  amountUncollected?: number | null;
250	  partnerProfit?: number | null;
251	  taxes?: number | null;
252	  advance?: number | null;
253	  previousBalance?: number | null;
254	  balanceCorrection?: number | null;
255	  currentBalance?: number | null;
256	  /** May be a number or a display string such as '-' */
257	  variance?: number | string | null;
258	};
259	
260	/**
261	 * Applies the reviewer scale factors to report-level summary financial fields.
262	 *
263	 * Scales money-in related fields (amountCollected, amountToCollect, amountUncollected, partnerProfit, variance) with moneyInScale.
264	 * Scales money-out related fields (taxes, advance, previousBalance, balanceCorrection, currentBalance) with moneyOutScale.
265	 *
266	 * Fast-paths when both scales === 1 so non-reviewer traffic pays no allocation cost.
267	 * Non-numeric `variance` values (display strings) are passed through unchanged.
268	 */
269	export function scaleReportFinancials<T extends ReportFinancials>(
270	  report: T,
271	  moneyInScale: number,
272	  moneyOutScale: number
273	): T {
274	  if (
275	    !report ||
276	    typeof report !== 'object' ||
277	    typeof moneyInScale !== 'number' ||
278	    typeof moneyOutScale !== 'number'
279	  ) {
280	    console.error(
281	      '[scaleReportFinancials] report (object), moneyInScale (number), and moneyOutScale (number) are required'
282	    );
283	    return report;
284	  }
285	
286	  if (moneyInScale === 1 && moneyOutScale === 1) return report;
287	
288	  return {
289	    ...report,
290	    amountCollected: Math.round((report.amountCollected ?? 0) * moneyInScale * 100) / 100,
291	    amountToCollect: Math.round((report.amountToCollect ?? 0) * moneyInScale * 100) / 100,
292	    amountUncollected: Math.round((report.amountUncollected ?? 0) * moneyInScale * 100) / 100,
293	    partnerProfit: Math.round((report.partnerProfit ?? 0) * moneyInScale * 100) / 100,
294	    taxes: Math.round((report.taxes ?? 0) * moneyOutScale * 100) / 100,
295	    advance: Math.round((report.advance ?? 0) * moneyOutScale * 100) / 100,
296	    previousBalance: Math.round((report.previousBalance ?? 0) * moneyOutScale * 100) / 100,
297	    balanceCorrection: Math.round((report.balanceCorrection ?? 0) * moneyOutScale * 100) / 100,
298	    currentBalance: Math.round((report.currentBalance ?? 0) * moneyOutScale * 100) / 100,
299	    variance:
300	      typeof report.variance === 'number'
301	        ? Math.round(report.variance * moneyInScale * 100) / 100
302	        : report.variance,
303	  };
304	}
305

