26	export default function Chart({
27	  loadingChartData,
28	  chartData,
29	  activeMetricsFilter,
30	  granularity,
31	}: ChartProps) {
32	  // ============================================================================
33	  // State & Hooks
34	  // ============================================================================
35	  // State for selected metrics (all selected by default)
36	  const [selectedMetrics, setSelectedMetrics] = useState<string[]>(() => {
37	    return ['Money In', 'Money Out', 'Jackpot', 'Gross'];
38	  });
39	  const { displayCurrency } = useCurrencyFormat();
40	  // Chart data received for rendering
41	
42	  // Always show skeleton when loading or if we have no data state yet
43	  if (loadingChartData || chartData === null) {
44	    return <DashboardChartSkeleton />;
45	  }
46	
47	  // ============================================================================
48	  // Computed
49	  // ============================================================================
50	  // Check if chartData is valid and has data
51	  const hasValidData =
52	    chartData && Array.isArray(chartData) && chartData.length > 0;
53	
54	  // If we have no valid data after loading is complete, show no data message
55	  if (!hasValidData) {
56	    // Show no data message only if we're not in initial loading state
57	    // If totals is explicitly null or undefined AND we're not loading, show the message
58	    return (
59	      <div className="flex flex-col items-center justify-center rounded-lg bg-container p-8 shadow-md">
60	        <div className="mb-2 text-lg text-gray-500">No Metrics Data</div>
61	        <div className="text-center text-sm text-gray-400">
62	          No metrics data available for the selected time period
63	        </div>
64	      </div>
65	    );
66	  }
67	
68	  // --- Robust sorting for both string and date types ---
69	  const parseTime = (val?: string, day?: string) => {
70	    if (!val || !day) return 0;
71	    try {
72	      const date = new Date(`${day}T${val}:00Z`);
73	      if (!isNaN(date.getTime())) {
74	        return date.getHours() * 60 + date.getMinutes();
75	      }
76	      // Fallback for independent time parsing
77	      const [h, m] = val.split(':').map(Number);
78	      return (h || 0) * 60 + (m || 0);
79	    } catch {
80	      return 0;
81	    }
82	  };
83	
84	  const parseDay = (val?: string) => {
85	    if (!val) return 0;
86	    try {
87	      // Explicitly handle YYYY-MM format for monthly data
88	      if (/^\d{4}-\d{2}$/.test(val)) {
89	        return new Date(`${val}-01`).getTime();
90	      }
91	      return new Date(val).getTime();
92	    } catch {
93	      return 0;
94	    }
95	  };
96	
97	  // Determine if we should use hourly or daily formatting
98	  // Respects the granularity prop - if daily/weekly/monthly is set, use that instead of hourly
99	  const shouldUseHourlyFormat = () => {
100	    // If granularity is explicitly set to daily, weekly, or monthly, don't use hourly format
101	    if (
102	      granularity === 'daily' ||
103	      granularity === 'weekly' ||
104	      granularity === 'monthly'
105	    ) {
106	      return false;
107	    }
108	
109	    // Trust an explicit hourly/minute granularity from the parent so the
110	    // chart always uses a time-axis for these cases — including custom ranges
111	    // where the data may straddle midnight (gaming day boundary) and therefore
112	    // contain more than one unique calendar day.
113	    if (granularity === 'hourly' || granularity === 'minute') {
114	      return true;
115	    }
116	
117	    // Legacy fallbacks for callers that don't pass a granularity prop
118	    if (
119	      activeMetricsFilter === 'Today' ||
120	      activeMetricsFilter === 'Yesterday'
121	    ) {
122	      return true;
123	    }
124	
125	    if (activeMetricsFilter === 'Custom') {
126	      // Fallback: infer from data when no granularity prop is provided
127	      const uniqueDays = new Set(chartData.map(d => d.day).filter(Boolean));
128	      return uniqueDays.size === 1;
129	    }
130	
131	    // All other values (7d, 30d, last7days, last30days, etc.) use daily format
132	    return false;
133	  };
134	
135	  // Detect if chart data has minute-level detail (for custom time ranges, Today, or Yesterday)
136	  const hasMinuteLevelData = () => {
137	    // Check for minute-level data in any time period
138	    return chartData.some(d => {
139	      const time = d.time;
140	      if (!time) return false;
141	      const timeParts = time.split(':');
142	      if (timeParts.length !== 2) return false;
143	      const minutes = parseInt(timeParts[1], 10);
144	      return !isNaN(minutes) && minutes !== 0; // Has non-zero minutes
145	    });
146	  };
147	
148	  const isHourlyChart = shouldUseHourlyFormat();
149	  const isMinuteLevel = hasMinuteLevelData();
150	
151	  // For hourly charts, filter to only the most common day
152	  // BUT: For minute-level data, don't filter by day - show all data points
153	  // This ensures minute data for Today shows all waves, even if gaming day spans calendar days
154	  // For Custom periods, skip day-filtering entirely — gaming day ranges straddle two calendar days
155	  // (e.g. Feb 1 8 AM → Feb 2 7:59 AM) and filtering to the most-common day drops half the data.
156	  let dayFilteredChartData = chartData;
157	  if (isHourlyChart && !isMinuteLevel && activeMetricsFilter !== 'Custom') {
158	    const dayCounts: Record<string, number> = {};
159	    chartData.forEach(d => {
160	      if (d.day) dayCounts[d.day] = (dayCounts[d.day] || 0) + 1;
161	    });
162	    const [mostCommonDay] =
163	      Object.entries(dayCounts).sort((a, b) => b[1] - a[1])[0] || [];
164	    if (mostCommonDay) {
165	      dayFilteredChartData = chartData.filter(
166	        data => data.day === mostCommonDay
167	      );
168	    }
169	  }
170	
171	  const sortedChartData = dayFilteredChartData.slice().sort((a, b) => {
172	    // If using hourly format, sort by day then time
173	    if (isHourlyChart) {
174	      const dayDiff = parseDay(a.day) - parseDay(b.day);
175	      if (dayDiff !== 0) return dayDiff;
176	      return parseTime(a.time, a.day) - parseTime(b.time, b.day);
177	    }
178	    // Otherwise, sort by day (could be string or date)
179	    return parseDay(a.day) - parseDay(b.day);
180	  });
181	
182	  // For hourly charts, we need to aggregate the data by hour to avoid showing individual meter readings
183	  // BUT: Don't aggregate if data already contains minute-level detail (for custom time ranges)
184	  let finalChartData = sortedChartData;
185	
186	  if (isHourlyChart && !isMinuteLevel) {
187	    // Group by hour and sum the values (only for hourly data, not minute-level)
188	    const hourlyData: Record<string, dashboardData> = {};
189	
190	    sortedChartData.forEach(item => {
191	      if (!item.time) return;
192	
193	      // Extract hour from time (e.g., "22:40" -> "22:00", "00:50" -> "00:00")
194	      const hour = item.time.split(':')[0] + ':00';
195	      const key = `${item.day}_${hour}`;
196	
197	      if (!hourlyData[key]) {
198	        hourlyData[key] = {
199	          xValue: `${item.day}_${hour}`,
200	          day: item.day,
201	          time: hour,
202	          moneyIn: 0,
203	          moneyOut: 0,
204	          gross: 0,
205	          location: item.location,
206	          geoCoords: item.geoCoords,
207	        };
208	      }
