23	/**
24	 * Builds aggregation pipeline for machine analytics
25	 *
26	 * @param allowedLocationIds - Location IDs to filter by, or 'all' for no filter
27	 * @param selectedLocation - Optional specific location to filter by
28	 * @param selectedLicencee - Optional licencee to filter by
29	 * @param limit - Optional limit for results
30	 * @returns Aggregation pipeline stages
31	 */
32	function buildMachineAnalyticsPipeline(
33	  allowedLocationIds: string[] | 'all',
34	  selectedLocation?: string,
35	  selectedLicencee?: string,
36	  limit?: number
37	): PipelineStage[] {
38	  if (allowedLocationIds !== 'all' && !Array.isArray(allowedLocationIds)) {
39	    console.error(
40	      '[buildMachineAnalyticsPipeline] allowedLocationIds must be array or "all"'
41	    );
42	    return [];
43	  }
44	  const pipeline: PipelineStage[] = [];
45	
46	  // Stage 1: Filter machines by allowed locations (supports legacy field names)
47	  if (allowedLocationIds !== 'all') {
48	    pipeline.push({
49	      $match: {
50	        $or: [
51	          { locationId: { $in: allowedLocationIds } },
52	          { gamingLocation: { $in: allowedLocationIds } },
53	        ],
54	      },
55	    } as PipelineStage);
56	  }
57	
58	  // Stage 1b: Optional specific location filter
59	  if (selectedLocation) {
60	    pipeline.push({
61	      $match: {
62	        $or: [
63	          { locationId: selectedLocation },
64	          { gamingLocation: selectedLocation },
65	        ],
66	      },
67	    } as PipelineStage);
68	  }
69	
70	  // Stage 2: Join machines with locations to get location details
71	  pipeline.push({
72	    $lookup: {
73	      from: 'gaminglocations',
74	      localField: 'locationId',
75	      foreignField: '_id',
76	      as: 'locationDetails',
77	    },
78	  });
79	
80	  // Stage 3: Flatten the location details array
81	  pipeline.push({
82	    $unwind: '$locationDetails',
83	  });
84	
85	  // Stage 4: Filter by licencee if provided
86	  if (selectedLicencee) {
87	    pipeline.push({
88	      $match: {
89	        $or: [{ 'locationDetails.rel.licencee': selectedLicencee }],
90	      },
91	    } as PipelineStage);
92	  }
93	
94	  // Stage 5: Project only the fields needed for analytics
95	  pipeline.push({
96	    $project: {
97	      _id: 1,
98	      name: 1,
99	      locationName: '$locationDetails.name',
100	      totalDrop: 1,
101	      gross: 1,
102	      isOnline: 1,
103	      hasSas: 1,
104	    },
105	  });
106	
107	  // Stage 6: Sort machines by total drop in descending order
108	  pipeline.push({
109	    $sort: {
110	      totalDrop: -1,
111	    },
112	  });
113	
114	  // Stage 7: Apply limit if specified
115	  if (limit) {
116	    pipeline.push({ $limit: limit });
117	  }
118	
119	  return pipeline;
120	}
