35	} from '@/app/api/lib/helpers/cabinets/cabinetListOperations';
36	
37	const functionName = '/api/cabinets';
38	
39	/**
40	 * GET handler for fetching cabinets
41	 *
42	 * Flow:
43	 * 1. Parse query params (id, locationId, checkSerial/Smib/CustomName, archived)
44	 * 2. If availability check → check duplicates
45	 * 3. If single ID → fetch one cabinet
46	 * 4. If locationId → filter by location, sort, return
47	 */
48	export async function GET(request: NextRequest) {
49	  const startTime = Date.now();
50	  const user = extractUserFromRequest(request);
51	
52	  return withApiAuth(request, async () => {
53	    try {
54	      // ============================================================================
55	      // STEP 1: Parse Query Params
56	      // ============================================================================
57	      const { searchParams } = request.nextUrl;
58	      const id = searchParams.get('id');
59	      const locationId = searchParams.get('locationId');
60	      const serialNumberToCheck = searchParams.get('checkSerial');
61	      const smibToCheck = searchParams.get('checkSmib');
62	      const customNameToCheck = searchParams.get('checkCustomName');
63	      const excludeId = searchParams.get('excludeId');
64	      const showArchived = searchParams.get('archived') === 'true';
65	
66	      // ============================================================================
67	      // STEP 2: Availability Check
68	      // ============================================================================
69	      if (serialNumberToCheck || smibToCheck || customNameToCheck) {
70	        const available = await checkCabinetAvailability(
71	          serialNumberToCheck,
72	          smibToCheck,
73	          customNameToCheck,
74	          excludeId
75	        );
76	        logRouteFetch(
77	          functionName,
78	          'GET',
79	          '/api/cabinets',
80	          1,
81	          user,
82	          Date.now() - startTime
83	        );
84	        return NextResponse.json({ success: true, available });
85	      }
86	
87	      if (!id && !locationId) {
88	        logRouteError(
89	          functionName,
90	          'GET',
91	          '/api/cabinets',
92	          'ID or locationId required',
93	          user
94	        );
95	        return NextResponse.json(
96	          { success: false, error: 'ID or locationId required' },
97	          { status: 400 }
98	        );
99	      }
100	
101	      // ============================================================================
102	      // STEP 3: Single Cabinet by ID
103	      // ============================================================================
104	      if (id) {
105	        const cabinet = await getCabinetById(id);
106	        if (!cabinet) {
107	          logRouteError(
108	            functionName,
109	            'GET',
110	            '/api/cabinets',
111	            `Not found: ${id}`,
112	            user
113	          );
114	          return NextResponse.json(
115	            { success: false, error: 'Not found' },
116	            { status: 404 }
117	          );
118	        }
119	        logRouteFetch(
120	          functionName,
121	          'GET',
122	          '/api/cabinets',
123	          1,
124	          user,
125	          Date.now() - startTime
126	        );
127	        return NextResponse.json({ success: true, data: cabinet });
128	      }
129	
130	      // ============================================================================
131	      // STEP 4: Cabinets by Location
132	      // ============================================================================
133	      const hasAccess = await checkUserLocationAccess(locationId as string);
134	      if (!hasAccess) {
135	        logRouteError(
