1	/**
2	 * Unified Cabinet Detail API Route
3	 *
4	 * This route provides a centralized endpoint for all cabinet-specific operations,
5	 * merging functionality from legacy machine and location-scoped routes.
6	 *
7	 * It supports:
8	 * - GET: Fetch cabinet details with financial metrics and currency conversion
9	 * - PUT: Full update of cabinet configuration and related collections
10	 * - PATCH: Partial updates (restore, collection settings, SMIB config)
11	 * - DELETE: Soft/Hard deletion of cabinets
12	 *
13	 * @module app/api/cabinets/[cabinetId]/route
14	 */
15	
16	import { checkUserLocationAccess } from '@/app/api/lib/helpers/licenceeFilter';
17	import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
18	import { connectDB } from '@/app/api/lib/middleware/db';
19	import { Machine } from '@/app/api/lib/models/machines';
20	import {
21	  logRouteFetch,
22	  logRouteUpdate,
23	  logRouteDelete,
24	  logRouteError,
25	  extractUserFromRequest,
26	} from '@/app/api/lib/utils/routeLogger';
27	import {
28	  aggregateCabinetMetrics,
29	  buildCabinetResponse,
30	  convertCabinetCurrency,
31	  fetchLocationSettings,
32	  performCabinetDelete,
33	  performCabinetPatch,
34	  performCabinetRestore,
35	  performCabinetUpdate,
36	} from '@/app/api/lib/helpers/cabinets/cabinetDetailOperations';
37	import type { MachineDocument } from '@/lib/types/common';
38	import type { CurrencyCode } from '@/shared/types/currency';
39	import type { TimePeriod } from '@/shared/types/common';
40	import { NextRequest, NextResponse } from 'next/server';
41	
42	/**
43	 * GET /api/cabinets/[cabinetId]
