1	/**
2	 * Cabinets Page Content Component
3	 *
4	 * Main content component that orchestrates all data fetching, state management,
5	 * and renders the cabinets management interface.
6	 *
7	 * @module components/cabinets/CabinetsPageContent
8	 */
9	'use client';
10	
11	import { CabinetsActions } from '@/components/CMS/cabinets/CabinetsActions';
12	import { CabinetsCabinetContentDisplay } from '@/components/CMS/cabinets/CabinetsCabinetContentDisplay';
13	import { CabinetsCabinetSearchFilters } from '@/components/CMS/cabinets/CabinetsCabinetSearchFilters';
14	import CabinetsNavigation from '@/components/CMS/cabinets/CabinetsNavigation';
15	import DashboardChart from '@/components/CMS/dashboard/DashboardChart';
16	import PageLayout from '@/components/shared/layout/PageLayout';
17	import { AccessRestricted } from '@/components/shared/ui/AccessRestricted';
18	import DateFilters from '@/components/shared/ui/common/DateFilters';
19	import FinancialMetricsCards from '@/components/shared/ui/FinancialMetricsCards';
20	import UploadSmibDataModal from '@/components/shared/ui/firmware/UploadSmibDataModal';
21	import MachineStatusWidget from '@/components/shared/ui/MachineStatusWidget';
22	import NewMovementRequestModal from '@/components/shared/ui/movements/NewMovementRequestModal';
23	import { NoLicenceeAssigned } from '@/components/shared/ui/NoLicenceeAssigned';
24	import { useCabinetsPageData } from '@/lib/hooks/cabinets/useCabinetsPageData';
25	import { useDashBoardStore } from '@/lib/store/dashboardStore';
26	import { useUserStore } from '@/lib/store/userStore';
27	import { shouldShowNoLicenceeMessage } from '@/lib/utils/licencee';
28	import { Info, MonitorPlay, Package, RefreshCw, Settings, Wrench } from 'lucide-react';
29	import dynamic from 'next/dynamic';
30	import CabinetsDeleteCabinetModal from './modals/CabinetsDeleteCabinetModal';
31	import CabinetsEditCabinetModal from './modals/CabinetsEditCabinetModal';
32	import CabinetsNewCabinetModal from './modals/CabinetsNewCabinetModal';
33	const CabinetsMovementRequests = dynamic(
34	  () => import('@/components/CMS/cabinets/CabinetsMovementRequests'),
35	  { ssr: false }
36	);
37	const CabinetsSMIBManagementTab = dynamic(
38	  () => import('@/components/CMS/cabinets/CabinetsSMIBManagementTab'),
39	  { ssr: false }
40	);
41	const SMIBFirmwareSection = dynamic(
42	  () => import('@/components/shared/ui/firmware/SMIBFirmwareSection'),
43	  { ssr: false }
44	);
45	
46	const CABINET_TABS_CONFIG = [
47	  { id: 'cabinets' as const, label: 'Cabinets', icon: MonitorPlay },
48	  { id: 'movement' as const, label: 'Movement Requests', icon: Package },
49	  { id: 'smib' as const, label: 'SMIB Management', icon: Settings },
50	  { id: 'firmware' as const, label: 'Firmware', icon: Wrench },
51	];
52	
53	const EXCLUDED_MOVEMENT_ROLES = ['collector'];
54	
55	export default function CabinetsPageContent() {
56	  // ============================================================================
57	  // Hooks & State
58	  // ============================================================================
59	  const cabinetsPageData = useCabinetsPageData();
60	  const { user } = useUserStore();
61	  const { setSelectedLicencee, activeMetricsFilter } = useDashBoardStore();
62	
63	  const {
64	    activeSection,
65	    loading,
66	    refreshing,
67	    error,
68	    locations,
69	    gameTypes,
70	    financialTotals,
71	    metricsTotals,
72	    metricsTotalsLoading,
73	    machineStats,
74	    paginatedCabinets,
75	    allCabinets,
76	    filteredCabinets,
77	    initialLoading,
78	    currentPage,
79	    sortOption,
80	    sortOrder,
81	    searchTerm,
82	    selectedLocation,
83	    selectedGameType,
84	    selectedStatus,
85	    selectedMembership,
86	    selectedSmibStatus,
87	    isNewMovementOpen,
88	    isUploadSmibOpen,
89	    refreshTrigger,
90	    chartData,
91	    loadingChart,
92	    totalPages,
93	    hasMoreCabinets,
94	    setActiveSection,
95	    setSearchTerm,
96	    setSelectedLocation,
97	    setSelectedGameType,
98	    setSelectedStatus,
99	    setSelectedMembership,
100	    setSelectedSmibStatus,
101	    setCurrentPage,
102	    handleColumnSort,
103	    handleRefresh,
104	    setIsNewMovementOpen,
105	    setIsUploadSmibOpen,
106	    loadCabinets,
107	    transformCabinet,
108	  } = cabinetsPageData;
109	
110	  // ============================================================================
111	  // Computed Values
112	  // ============================================================================
113	  const userRoles = (user?.roles || []).filter(
114	    (r): r is string => typeof r === 'string'
115	  );
116	  const isTechnicianOnly =
117	    userRoles.includes('technician') &&
118	    !userRoles.some(r =>
119	      ['admin', 'developer', 'manager', 'location admin'].includes(r)
120	    );
121	  // ============================================================================
122	  // Permission Checks
123	  // ============================================================================
124	  // If user has no licencee assigned, show the "No Licencee Assigned" message
125	  if (shouldShowNoLicenceeMessage(user)) {
126	    return (
127	      <PageLayout
128	        headerProps={{ setSelectedLicencee }}
129	        mainClassName="flex flex-col flex-1 p-4 md:p-6"
130	        showToaster={false}
131	      >
132	        <NoLicenceeAssigned />
133	      </PageLayout>
134	    );
135	  }
136	
137	  // ============================================================================
138	  // Render
139	  // ============================================================================
140	  return (
141	    <>
142	      {/* Modal Components */}
143	      <CabinetsEditCabinetModal onCabinetUpdated={handleRefresh} />
144	      <CabinetsDeleteCabinetModal onCabinetDeleted={handleRefresh} />
145	      <CabinetsNewCabinetModal
146	        locations={locations}
147	        onCreated={handleRefresh}
148	      />
149	      <NewMovementRequestModal
150	        isOpen={isNewMovementOpen}
151	        onClose={() => setIsNewMovementOpen(false)}
152	        locations={locations}
153	        onSubmit={async () => {
154	          setIsNewMovementOpen(false);
155	          await handleRefresh();
156	        }}
157	      />
158	      <UploadSmibDataModal
159	        isOpen={isUploadSmibOpen}
160	        onClose={() => setIsUploadSmibOpen(false)}
161	        onRefresh={loadCabinets}
162	      />
163	
164	      <PageLayout
165	        headerProps={{ setSelectedLicencee }}
166	        mainClassName="flex flex-col flex-1 p-4 md:p-6"
167	        showToaster={false}
168	        onRefresh={handleRefresh}
169	        refreshing={refreshing}
170	      >
171	        {/* Page Header: Title, refresh button, and action buttons */}
172	        <div className="mb-6 mt-4 flex items-center justify-between">
173	          <h1 className="text-2xl font-bold text-gray-800 sm:text-3xl">
174	            Cabinets
175	          </h1>
176	          <div className="flex items-center gap-2">
177	            <button
178	              onClick={handleRefresh}
179	              disabled={refreshing}
180	              className="p-2 text-gray-600 transition-colors hover:text-gray-900 disabled:opacity-50"
181	              aria-label="Refresh data"
182	            >
183	              <RefreshCw
184	                className={`h-5 w-5 ${refreshing ? 'animate-spin' : ''}`}
185	              />
186	            </button>
187	            <CabinetsActions
188	              activeSection={activeSection}
189	              selectedLocation={selectedLocation}
190	              locations={locations}
191	              onMovementRequestClick={() => setIsNewMovementOpen(true)}
192	              onCabinetCreated={loadCabinets}
193	              onCabinetUpdated={loadCabinets}
194	              onCabinetDeleted={loadCabinets}
195	              loading={loading}
196	            />
197	          </div>
198	        </div>
199	
200	        {/* Tab Navigation Section */}
201	        <CabinetsNavigation
202	          tabs={CABINET_TABS_CONFIG.filter(tab => {
203	            if (tab.id === 'movement') {
204	              const userRoles = (user?.roles || []).filter(
205	                (r): r is string => typeof r === 'string'
206	              );
207	              return !userRoles.some((role: string) =>
208	                EXCLUDED_MOVEMENT_ROLES.includes(role)
209	              );
210	            }
211	            return true;
212	          })}
213	          activeSection={activeSection}
214	          onChange={setActiveSection}
215	        />
216	
217	        {/* Include Jackpot Indicator */}
218	        {cabinetsPageData.includeJackpot && (
219	          <div className="mt-4 flex items-center gap-2 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2">
220	            <Info className="h-4 w-4 flex-shrink-0 text-amber-600" />
221	            <p className="text-xs font-medium text-amber-800">
222	              Jackpot is included in Money Out for this licencee
223	            </p>
224	          </div>
225	        )}
226	
227	        {/* ============================================================================
228	           Tab Content: Main Cabinets View
229	           ============================================================================ */}
230	        {activeSection === 'cabinets' && (
231	          <div className="mt-6 w-full max-w-full overflow-x-hidden">
232	            {/* Financial Metrics Summary Cards */}
233	            {false && (
234	              <div className="mb-6 w-full max-w-full">
235	                <FinancialMetricsCards
236	                  totals={metricsTotals || financialTotals}
237	                  loading={loading || metricsTotalsLoading}
238	                  title="Total for all Machines"
239	                  includeJackpot={cabinetsPageData.includeJackpot}
240	                />
241	              </div>
242	            )}
243	
244	            {/* Performance Visualization Chart */}
245	            {false && (
246	              <div className="mb-6 w-full max-w-full">
247	                {/* Granularity Selector for Last 30 Days and Quarterly */}
248	                {(activeMetricsFilter === '30d' ||
249	                  activeMetricsFilter === 'last30days' ||
250	                  activeMetricsFilter === 'Quarterly') &&
251	                  !loadingChart && (
252	                    <div className="mb-3 flex items-center justify-end gap-2">
253	                      <label
254	                        htmlFor="chart-granularity-cabinets"
255	                        className="text-sm font-medium text-gray-700 dark:text-gray-300"
256	                      >
257	                        Granularity:
258	                      </label>
259	                      <select
260	                        id="chart-granularity-cabinets"
261	                        value={cabinetsPageData.chartGranularity}
262	                        onChange={e =>
263	                          cabinetsPageData.setChartGranularity(
264	                            e.target.value as 'daily' | 'weekly' | 'monthly'
265	                          )
266	                        }
267	                        className="rounded-md border border-gray-300 bg-white px-3 py-1.5 text-sm shadow-sm focus:border-blue-500 focus:outline-none focus:ring-1 focus:ring-blue-500 dark:border-gray-600 dark:bg-gray-800 dark:text-gray-200"
268	                      >
269	                        {activeMetricsFilter === 'Quarterly' ? (
270	                          <>
271	                            <option value="monthly">Monthly</option>
272	                            <option value="weekly">Weekly</option>
273	                          </>
274	                        ) : (
275	                          <>
276	                            <option value="daily">Daily</option>
277	                            <option value="weekly">Weekly</option>
278	                          </>
279	                        )}
280	                      </select>
281	                    </div>
282	                  )}
283	                <DashboardChart
284	                  loadingChartData={loadingChart}
285	                  chartData={chartData}
286	                  activeMetricsFilter={activeMetricsFilter}
287	                  granularity={cabinetsPageData.chartGranularity}
288	                />
289	              </div>
290	            )}
291	
292	            {/* Filter Controls Row: Date selection and machine status widget */}
293	            <div className="mb-6 mt-4 flex flex-col justify-between gap-4 xl:flex-row xl:items-end">
294	              <div className="order-1">
295	                {isTechnicianOnly ? (
296	                  <div className="flex h-10 items-center rounded-lg bg-blue-50 px-4 text-sm font-medium text-blue-700">
297	                    <span className="mr-2 italic">
298	                      Showing data within the last hour
299	                    </span>
300	                  </div>
301	                ) : (
302	                  <DateFilters
303	                    hideAllTime
304	                    showQuarterly
305	                    onCustomRangeGo={loadCabinets}
306	                    enableTimeInputs
307	                  />
308	                )}
309	              </div>
310	              <div className="order-2">
311	                <MachineStatusWidget
312	                  isLoading={refreshing}
313	                  onlineCount={machineStats?.onlineMachines ?? 0}
314	                  offlineCount={machineStats?.offlineMachines ?? 0}
315	                  totalCount={machineStats?.totalMachines ?? 0}
316	                  showTotal
317	                />
318	              </div>
319	            </div>
320	
321	            {/* Search & Advanced Filters */}
322	            <div className="relative w-full max-w-full overflow-visible">
323	              <CabinetsCabinetSearchFilters
324	                searchTerm={searchTerm}
325	                onSearchChange={setSearchTerm}
326	                selectedLocation={selectedLocation}
327	                locations={locations}
328	                onLocationChange={setSelectedLocation}
329	                selectedGameType={selectedGameType}
330	                gameTypes={gameTypes}
331	                onGameTypeChange={setSelectedGameType}
332	                selectedStatus={selectedStatus}
333	                onStatusChange={setSelectedStatus}
334	                selectedMembership={selectedMembership}
335	                onMembershipChange={setSelectedMembership}
336	                selectedSmibStatus={selectedSmibStatus}
337	                onSmibStatusChange={setSelectedSmibStatus}
338	                sortOption={sortOption}
339	                sortOrder={sortOrder}
340	                onSortChange={handleColumnSort}
341	                activeSection={activeSection}
342	                showLocationFilter={true}
343	              />
344	            </div>
345	
346	            {/* Cabinet Listing: Table and Mobile Card Views */}
347	            <div className="w-full max-w-full overflow-x-hidden">
348	              <CabinetsCabinetContentDisplay
349	                paginatedCabinets={paginatedCabinets}
350	                filteredCabinets={filteredCabinets || paginatedCabinets}
351	                allCabinets={allCabinets || paginatedCabinets}
352	                initialLoading={initialLoading || false}
353	                loading={loading}
354	                error={error}
355	                sortOption={sortOption}
356	                sortOrder={sortOrder}
357	                currentPage={currentPage}
358	                totalPages={totalPages}
359	                onPageChange={setCurrentPage}
360	                hasMore={hasMoreCabinets}
361	                onSort={handleColumnSort}
362	                onEdit={() => {}}
363	                onDelete={() => {}}
364	                onRetry={loadCabinets}
365	                transformCabinet={transformCabinet}
366	                includeJackpot={cabinetsPageData.includeJackpot}
367	                showArchived={selectedStatus === 'Archived'}
368	              />
369	            </div>
370	          </div>
371	        )}
372	
373	        {/* ============================================================================
374	           Tab Content: SMIB Management
375	           ============================================================================ */}
376	        {activeSection === 'smib' && (
377	          <CabinetsSMIBManagementTab refreshTrigger={refreshTrigger} />
378	        )}
379	
380	        {/* ============================================================================
381	           Tab Content: Movement Requests
382	           ============================================================================ */}
383	        {activeSection === 'movement' &&
384	          (() => {
385	            const userRoles = (user?.roles || []).filter(
386	              (r): r is string => typeof r === 'string'
387	            );
388	            const isAuthorized = !userRoles.some((role: string) =>
389	              EXCLUDED_MOVEMENT_ROLES.includes(role)
390	            );
391	
392	            if (!isAuthorized) {
393	              return <AccessRestricted sectionName="Movement Requests" />;
394	            }
395	
396	            return (
397	              <CabinetsMovementRequests
398	                locations={locations}
399	                refreshTrigger={refreshTrigger}
400	              />
401	            );
402	          })()}
403	
404	        {/* ============================================================================
405	           Tab Content: Firmware Management
406	           ============================================================================ */}
407	        {activeSection === 'firmware' && (
408	          <SMIBFirmwareSection refreshTrigger={refreshTrigger} />
409	        )}
410	      </PageLayout>
411	    </>
412	  );
413	}
