// ============================================================================
// Chart Logic
// ============================================================================
const [chartGranularity, setChartGranularity] = useState<
  'hourly' | 'minute' | 'daily' | 'weekly' | 'monthly'
>(() =>
  getDefaultChartGranularity(
    activeMetricsFilter || 'Today',
    customDateRange?.startDate,
    customDateRange?.endDate
  )
);
type ChartDataPoint = {
  xValue: string;
  day: string;
  time: string;
  moneyIn: number;
  moneyOut: number;
  gross: number;
};

const [chartData, setChartData] = useState<ChartDataPoint[]>([]);
const [loadingChart, setLoadingChart] = useState(false);

// Recalculate default granularity when date filters change
useEffect(() => {
  if (!activeMetricsFilter) return;
  const defaultGranularity = getDefaultChartGranularity(
    activeMetricsFilter,
    customDateRange?.startDate,
    customDateRange?.endDate
  );
  setChartGranularity(defaultGranularity);
}, [
  activeMetricsFilter,
  customDateRange?.startDate,
  customDateRange?.endDate,
]);

const fetchChartData = useCallback(async () => {
  if (!activeMetricsFilter) return;
  setLoadingChart(true);
  try {
    await makeRequest(async signal => {
      // Pass granularity to API for short periods and 30d daily/weekly
      const apiGranularity:
        | 'hourly'
        | 'minute'
        | 'daily'
        | 'weekly'
        | 'monthly'
        | undefined =
        chartGranularity === 'minute'
          ? 'minute'
          : chartGranularity === 'hourly'
            ? 'hourly'
            : chartGranularity === 'daily'
              ? 'daily'
              : chartGranularity === 'weekly'
                ? 'weekly'
                : chartGranularity === 'monthly'
                  ? 'monthly'
                  : undefined;
      const data = await getMetrics(
        activeMetricsFilter as TimePeriod,
        customDateRange?.startDate,
        customDateRange?.endDate,
        selectedLicencee,
        displayCurrency,
        signal,
        apiGranularity,
        selectedLocation,
        selectedGameType,
        selectedStatus === 'All' || selectedStatus === 'all'
          ? 'all'
          : selectedStatus === 'Archived'
            ? 'archived'
            : selectedStatus,
        debouncedSearchTerm
      );
      if (data) {
        setChartData(
          data.map(dataItem => ({
            xValue: dataItem.time || dataItem.day,
            day: dataItem.day,
            time: dataItem.time ?? '',
            moneyIn: dataItem.moneyIn,
            moneyOut: dataItem.moneyOut,
            gross: dataItem.gross,
            netGross: dataItem.netGross,
          }))
        );
      }
    }, 'chart');
  } finally {
    setLoadingChart(false);
  }
}, [
  activeMetricsFilter,
  customDateRange,
  selectedLicencee,
  displayCurrency,
  chartGranularity,
  selectedLocation,
  selectedGameType,
  selectedStatus,
  debouncedSearchTerm,
  makeRequest,
]);

// ============================================================================
// Handlers
// ============================================================================
const handleRefresh = async () => {
  if (activeSection === 'cabinets') {
    setIsFilterResetting(true);
    await Promise.all([
      loadCabinets(currentPage + 1, ITEMS_PER_PAGE, sortOption, sortOrder),
      fetchChartData(),
      refreshMachineStats(),
    ]);
    setIsFilterResetting(false);
  } else {
    setRefreshTrigger(prev => prev + 1);
  }
};

  const [isUploadSmibOpen, setIsUploadSmibOpen] = useState(false);

  // Consolidated data fetch effect
  useEffect(() => {
    if (activeSection === 'cabinets' && activeMetricsFilter) {
      if (
        activeMetricsFilter === 'Custom' &&
        (!customDateRange?.startDate || !customDateRange?.endDate)
      ) {
        return;
      }

      const currentBatch = calculateBatchNumber(currentPage);

      // Fetch next batch if needed (using ref for synchronous check)
      if (!loadedBatchesRef.current.has(currentBatch)) {
        console.warn(
          `[useCabinetsPageData] Fetching batch ${currentBatch} for page ${currentPage + 1}`
        );
        loadedBatchesRef.current.add(currentBatch);
        void loadCabinets(currentBatch, ITEMS_PER_BATCH, sortOption, sortOrder);
      }

      void fetchChartData();
    }
  }, [
    currentPage,
    sortOption,
    sortOrder,
    selectedStatus,
    selectedMembership,
    selectedSmibStatus,
    selectedLocation,
    selectedGameType,
    activeSection,
    activeMetricsFilter,
    customDateRange,
    selectedLicencee,
    loadCabinets,
    fetchChartData,
    debouncedSearchTerm,
    batchResetCounter,
    calculateBatchNumber,
  ]);

  // isFilterResetting is cleared when data arrives
  useEffect(() => {
    if (!loading && isFilterResetting) {
      setIsFilterResetting(false);
    }
  }, [loading, isFilterResetting]);

  return {
    activeSection,
    loading:
      loading ||
      initialLoading ||
      isFilterResetting ||
      isDataMissingForPage ||
      searchTerm !== debouncedSearchTerm,
    refreshing:
      loading || machineStatsLoading || loadingChart || isFilterResetting,
    error,
    locations,
    gameTypes,
    financialTotals,
    metricsTotals,
    metricsTotalsLoading,
    machineStats,
    paginatedCabinets,
    allCabinets: filteredCabinets,
    filteredCabinets: filteredCabinets,
    initialLoading,
    currentPage,
    sortOption,
    sortOrder,
    searchTerm,
    selectedLocation,
    selectedGameType,
    selectedStatus,
    selectedMembership,
    selectedSmibStatus,
    chartGranularity,
    isNewMovementOpen,
    isUploadSmibOpen,
    refreshTrigger,
    totalCount,
    hasMoreCabinets,
    chartData,
    loadingChart,
    totalPages: effectiveTotalPages,
    includeJackpot,
    // Setters & Handlers
    setActiveSection,
    setSearchTerm: handleSetSearchTerm,
    setSelectedLocation: handleSetSelectedLocation,
    setSelectedGameType: handleSetSelectedGameType,
    setSelectedStatus: handleSetSelectedStatus,
    setSelectedMembership: handleSetSelectedMembership,
    setSelectedSmibStatus: handleSetSelectedSmibStatus,
    setChartGranularity,
    setCurrentPage,
    handleColumnSort,
    handleRefresh,
    setIsNewMovementOpen,
    setIsUploadSmibOpen,
    loadCabinets,
    transformCabinet,
  };
}

