import type {
  Address,
  AggregatedLocation,
  GeoCoordinates,
  RelationshipInfo,
} from '@/shared/types';

export type { AggregatedLocation };

export type UpdateLocationData = {
  name?: string;
  country?: string;
  address?: Partial<Address>;
  rel?: Partial<RelationshipInfo>;
  profitShare?: number;
  gameDayOffset?: number;
  geoCoords?: Partial<GeoCoordinates>;
  isLocalServer?: boolean;
  billValidatorOptions?: Record<string, unknown>;
  membershipEnabled?: boolean;
  locationMembershipSettings?: Record<string, unknown>;
  updatedAt?: Date;
  [key: string]: unknown;
};

export type LocationSelectItem = {
  _id: string;
  name: string;
  slug?: string;
  licenceeId?: string | null;
};

export type LocationSortOption =
  | 'locationName'
  | 'moneyIn'
  | 'moneyOut'
  | 'gross'
  | 'totalMachines'
  | 'onlineMachines'
  | 'default';

export type LocationFilter =
  | 'NoSMIBLocation'
  | 'FullSMIBs'
  | 'SemiSMIBs'
  | 'LocalServersOnly'
  | 'WowOnly'
  | 'MembershipOnly'
  | 'MissingCoordinates'
  | 'HasCoordinates'
  | ''
  | null;

export type LocationResponse = {
  _id: string;
  name: string;
  address: Address;
  city?: string;
  state?: string;
  country: string;
  licencee?: string;
  latitude?: number;
  longitude?: number;
  coordinates?: [number, number];
  metersIn?: number;
  metersOut?: number;
  jackpot?: number;
  gross?: number;
  timePeriod?: string;
  rel?: RelationshipInfo;
  profitShare?: number;
  geoCoords?: GeoCoordinates;
  totalMachines?: number;
  onlineMachines?: number;
  isLocalServer?: boolean;
  hasSmib?: boolean;
  membershipEnabled?: boolean;
  locationMembershipSettings?: Record<string, unknown>;
};

import { DateRangeFilter } from '../common/mongo';

export type MeterMatchStage = {
  readAt: DateRangeFilter;
  'rel.licencee'?: string;
  [key: string]: unknown;
};

export type LocationCardData = {
  location: AggregatedLocation;
  onLocationClick: (id: string) => void;
  onEdit: (location: AggregatedLocation) => void;
  onDelete: (location: AggregatedLocation) => void;
  onRestore: (location: AggregatedLocation) => void;
  formatCurrency: (amount: number) => string;
  canManageLocations?: boolean;
  isDeveloper?: boolean;
};

export type LocationTableProps = {
  canManageLocations?: boolean; // If false, hide edit/delete buttons
  isDeveloper?: boolean; // If true, show permanent delete button for archived locations
  locations: AggregatedLocation[];
