52	 * Main GET handler for searching all locations
53	 *
54	 * Flow:
55	 * 1. Parse query parameters (licencee, search, currency)
56	 * 2. Connect to database
57	 * 3. Get user's accessible licencees and permissions
58	 * 4. Build location match filter
59	 * 5. Fetch aggregated machine stats
60	 * 6. Compute financial metrics (gaming day ranges, meters)
61	 * 7. Build hydrated location result objects
62	 * 8. Apply online status filtering
63	 * 9. Apply currency conversion if needed
64	 * 10. Format and sort final response
65	 */
66	export async function GET(request: NextRequest) {
67	  const startTime = Date.now();
68	  const functionName = 'GET /api/locations/search-all';
69	  const user = extractUserFromRequest(request);
70	
71	  try {
72	    // ============================================================================
73	    // STEP 1: Parse query parameters
74	    // ============================================================================
75	    const { searchParams } = new URL(request.url);
76	    const licencee = searchParams.get('licencee') || '';
77	    const search = searchParams.get('search')?.trim() || '';
78	    const displayCurrency = (searchParams.get('currency') as CurrencyCode) || 'USD';
79	    const timePeriod = (searchParams.get('timePeriod') as TimePeriod) || '30d';
80	    const startDateParam = searchParams.get('startDate');
81	    const endDateParam = searchParams.get('endDate');
82	    const customStartDate = startDateParam ? new Date(startDateParam) : undefined;
83	    const customEndDate = endDateParam ? new Date(endDateParam) : undefined;
84	    const machineTypeFilter = searchParams.get('machineTypeFilter');
85	    const onlineStatus = searchParams.get('onlineStatus')?.toLowerCase() || 'all';
86	    const showArchived =
87	      searchParams.get('archived') === 'true' ||
88	      searchParams.get('includeDeleted') === 'true';
89	    const syncAll = searchParams.get('syncAll') === 'true';
90	
91	    // ============================================================================
92	    // STEP 2: Connect to database
93	    // ============================================================================
94	    const db = await connectDB();
95	    if (!db) {
96	      return NextResponse.json(
97	        { success: false, message: 'DB connection failed' },
98	        { status: 500 }
99	      );
100	    }
101	
102	    // ============================================================================
103	    // STEP 3: Get user's accessible licencees and permissions
104	    // ============================================================================
105	    const userAccessibleLicencees = await getUserAccessibleLicenceesFromToken();
106	    const userPayload = await getUserFromServer();
107	    const userRoles = (userPayload?.roles as string[]) || [];
108	    const userLocationPermissions: string[] = Array.isArray(
109	      (userPayload as { assignedLocations?: string[] })?.assignedLocations
110	    )
111	      ? (userPayload as { assignedLocations: string[] }).assignedLocations
112	      : [];
113	
114	    const allowedLocationIds = await getUserLocationFilter(
115	      userAccessibleLicencees,
116	      licencee || undefined,
117	      userLocationPermissions,
118	      userRoles
119	    );
120	
121	    if (allowedLocationIds !== 'all' && allowedLocationIds.length === 0) {
122	      return NextResponse.json([]);
123	    }
124	
125	    // ============================================================================
126	    // STEP 4: Build location match filter
127	    // ============================================================================
128	    // WOW filter has no persisted location flag — derive IDs from WOW machines.
129	    let wowLocationIds: string[] | null = null;
130	    if (machineTypeFilter?.split(',').some(type => type.trim() === 'WowOnly')) {
131	      const wowLocs = await Machine.distinct('gamingLocation', {
132	        'meta.dataSync.source': 'wow',
133	        $or: [
134	          { deletedAt: null },
135	          { deletedAt: { $lt: new Date('2025-01-01') } },
136	        ],
137	      });
138	      wowLocationIds = wowLocs.map(id => String(id));
139	    }
140	
141	    const locationMatch = buildLocationSearchFilter({
142	      showArchived,
143	      search,
144	      licencee,
145	      allowedLocationIds,
146	      machineTypeFilter,
147	      wowLocationIds,
148	    });
149	
150	    // ============================================================================
151	    // STEP 5: Fetch aggregated machine stats
152	    // ============================================================================
153	    const matchingLocations = await fetchMachineStats(locationMatch, showArchived);
154	
155	    // ============================================================================
156	    // STEP 6: Compute financial metrics
157	    // ============================================================================
158	    const {
159	      metersByLocation,
160	      memberCountMap,
161	      licenceeIncludeJackpotMap,
162	      allLocationIds,
163	      globalEnd,
164	    } = await computeFinancialMetrics(matchingLocations, timePeriod, customStartDate, customEndDate);
165	
166	    // Compute reviewer scales
167	    const moneyInScale = getMoneyInScale(
168	      userPayload as {
169	        moneyInMultiplier?: number | null;
170	        roles?: string[];
171	        reviewerMultiplierStartTime?: Date | string | null;
172	      },
173	      globalEnd
174	    );
175	    const moneyOutScale = getMoneyOutAndJackpotScale(
176	      userPayload as {
177	        moneyOutAndJackpotMultiplier?: number | null;
178	        roles?: string[];
179	        reviewerMultiplierStartTime?: Date | string | null;
180	      },
181	      globalEnd
182	    );
183	
184	    // Handle SMIB sync if requested
185	    if (syncAll && allLocationIds.length > 0) {
186	      console.log(
187	        `[Locations Search-All] syncAll=true - syncing SMIB for ${allLocationIds.length} locations`
188	      );
189	      const locationsWithMachines = await fetchLocationsWithMachinesForSmib(allLocationIds);
190	      await syncAllLocationSmibStatuses(locationsWithMachines);
191	    }
192	
193	    // ============================================================================
194	    // STEP 7: Build hydrated location result objects
195	    // ============================================================================
196	    const hydratedLocations = buildLocationResults({
197	      matchingLocations,
198	      metersByLocation,
199	      memberCountMap,
200	      licenceeIncludeJackpotMap,
201	      syncAll,
202	      moneyInScale,
203	      moneyOutScale,
204	    });
205	
206	    // ============================================================================
207	    // STEP 8: Apply online status filtering
208	    // ============================================================================
209	    const filteredLocations = applyOnlineFilterAndSort(hydratedLocations, onlineStatus);
210	
211	    // ============================================================================
212	    // STEP 9: Apply currency conversion
213	    // ============================================================================
214	    const { locations: convertedLocations } = await applyCurrencyConversion(
215	      filteredLocations,
216	      displayCurrency,
217	      licencee
218	    );
219	
220	    // ============================================================================
221	    // STEP 10: Format and sort final response
222	    // ============================================================================
223	    const finalResponse = formatSearchResponse(convertedLocations, search);
224	
225	    const duration = Date.now() - startTime;
226	    logRouteFetch(
227	      functionName,
228	      'GET',
229	      '/api/locations/search-all',
230	      finalResponse.length,
231	      user,
232	      duration
233	    );
234	
235	    if (duration > 2000) {
236	      console.warn(`[Locations Search All API] Completed in ${duration}ms`);
237	    }
238	
239	    return NextResponse.json(finalResponse);
240	  } catch (error) {
241	    const duration = Date.now() - startTime;
242	    const errorMessage =
