 * 10. Format and sort final response
 */
export async function GET(request: NextRequest) {
  const startTime = Date.now();
  const functionName = 'GET /api/locations/search-all';
  const user = extractUserFromRequest(request);

  try {
    // ============================================================================
    // STEP 1: Parse query parameters
    // ============================================================================
    const { searchParams } = new URL(request.url);
    const licencee = searchParams.get('licencee') || '';
    const search = searchParams.get('search')?.trim() || '';
    const displayCurrency = (searchParams.get('currency') as CurrencyCode) || 'USD';
    const timePeriod = (searchParams.get('timePeriod') as TimePeriod) || '30d';
    const startDateParam = searchParams.get('startDate');
    const endDateParam = searchParams.get('endDate');
    const customStartDate = startDateParam ? new Date(startDateParam) : undefined;
    const customEndDate = endDateParam ? new Date(endDateParam) : undefined;
    const machineTypeFilter = searchParams.get('machineTypeFilter');
    const onlineStatus = searchParams.get('onlineStatus')?.toLowerCase() || 'all';
    const showArchived =
      searchParams.get('archived') === 'true' ||
      searchParams.get('includeDeleted') === 'true';
    const syncAll = searchParams.get('syncAll') === 'true';

    // ============================================================================
    // STEP 2: Connect to database
