24	 *
25	 * @param {string} licencee - Filter count by licencee name
26	 * @param {string} locationId - Filter count by specific location ID
27	 *
28	 * Flow:
29	 * 1. Parse licencee parameter
30	 * 2. Connect to database and authenticate user
31	 * 3. Get user location permissions
32	 * 4. Count locations with membership enabled
33	 * 5. Return count
34	 */
35	export async function GET(req: NextRequest) {
36	  return withApiAuth(req, async ({ user, userRoles }) => {
37	    const startTime = Date.now();
38	    const functionName = 'GET /api/locations/membership-count';
39	    const logUser = extractUserFromRequest(req);
40	
41	    try {
42	      // ============================================================================
43	      // STEP 1: Parse request parameters
44	      // ============================================================================
45	      const { searchParams } = new URL(req.url);
46	      const licencee = searchParams.get('licencee');
47	      const locationId = searchParams.get('locationId');
48	
49	      // ============================================================================
50	      // STEP 2: Resolve user accessible licencees and permissions
51	      // ============================================================================
52	      const userAccessibleLicencees =
53	        await getUserAccessibleLicenceesFromToken();
54	
55	      // Get user's location permissions
56	      const userLocationPermissions = ((
57	        user.resourcePermissions as
58	          | Record<
59	              string,
60	              {
61	                resources?: Array<{ _id: string }>;
62	              }
63	            >
64	          | undefined
65	      )?.['gaming-locations']?.resources?.map(
66	        (resource: { _id: string }) => resource._id
67	      ) || []) as string[];
68	
69	      // ============================================================================
70	      // STEP 3: Get user location permissions
71	      // ============================================================================
72	      const allowedLocationIds = await getUserLocationFilter(
73	        userAccessibleLicencees,
74	        licencee || undefined,
75	        userLocationPermissions,
76	        userRoles
77	      );
78	
79	      // ============================================================================
80	      // STEP 4: Build query for membership-enabled locations
81	      // ============================================================================
82	      const query: Record<string, unknown> = {
83	        $and: [
84	          {
85	            $or: [
86	              { deletedAt: null },
87	              { deletedAt: { $lt: new Date('2025-01-01') } },
88	            ],
89	          },
90	          // Check both membershipEnabled and enableMembership fields for compatibility
91	          {
92	            $or: [{ membershipEnabled: true }, { enableMembership: true }],
93	          },
94	        ],
95	      };
96	
97	      // Apply location permissions
98	      if (allowedLocationIds !== 'all') {
99	        if (allowedLocationIds.length === 0) {
100	          return NextResponse.json({ membershipCount: 0 });
101	        }
102	        query._id = { $in: allowedLocationIds };
103	      }
104	
105	      // Apply licencee filter if provided
106	      if (licencee && licencee !== 'all') {
107	        query['rel.licencee'] = licencee;
108	      }
109	
110	      // Apply specific location filter if provided
111	      if (locationId) {
112	        query._id = locationId;
113	      }
114	
115	      // ============================================================================
116	      // STEP 5: Count locations with membership enabled
117	      // ============================================================================
118	      const membershipCount = await GamingLocations.countDocuments(query);
119	
120	      const duration = Date.now() - startTime;
121	      logRouteFetch(
122	        functionName,
123	        'GET',
124	        '/api/locations/membership-count',
125	        1,
126	        logUser,
127	        duration
128	      );
129	      if (duration > 1000) {
130	        console.warn(`[Membership Count API] Completed in ${duration}ms`);
131	      }
132	
133	      return NextResponse.json({ membershipCount });
134	    } catch (err) {
135	      const errorMessage = err instanceof Error ? err.message : 'Server Error';
136	      logRouteError(
137	        functionName,
138	        'GET',
139	        '/api/locations/membership-count',
140	        errorMessage,
141	        logUser
142	      );
143	      console.error('[API Error] Membership count:', errorMessage);
144	      return NextResponse.json(
145	        { error: errorMessage, membershipCount: 0 },
146	        { status: 500 }
147	      );
148	    }
149	  });
150	}

