/**
 * Vault Page (Root)
 *
 * Redirects the root `/vault` path to the default vault management view
 * at `/vault/management`.
 */

import { redirect } from 'next/navigation';

export default function VaultRootPage() {
  redirect('/vault/management');
}

/**
 * Collection by ID API Route
 *
 * This route handles updating a specific collection by ID.
 * It supports:
 * - Updating collection fields (meters, timestamps, notes, etc.)
 * - Recalculating movement and SAS metrics when meters change
 * - Recalculating SAS time ranges when timestamp changes
 * - Updating machine collectionMetersHistory
 * - Cascading recalculation to related collections
 *
 * @module app/api/collection-reports/collections/[id]/route
 */

import {
  cascadeRecalculationForPatch,
  determineRecalculationFlags,
  extractSasTimeFieldsFromPayload,
  handleRamClearToggleWithRelayGuard,
  logCollectionPatchActivity,
  recalculateMovementAndSasForPatch,
  updateMachineHistoryForPatch,
} from '@/app/api/lib/helpers/collectionReport/collectionByIdOperations';
import { Collections } from '@/app/api/lib/models/collections';
import { withApiAuth } from '@/app/api/lib/helpers/apiWrapper';
import { checkUserLocationAccess } from '@/app/api/lib/helpers/licenceeFilter';
import {
  logRouteUpdate,
  logRouteError,
  extractUserFromRequest,
} from '@/app/api/lib/utils/routeLogger';
import type { CollectionDocument } from '@/lib/types/collection';
import { NextRequest, NextResponse } from 'next/server';

/**
 * PATCH /api/collection-reports/collections/[id]
 *
 * EDITS a single collection document (NOT creation flow).
 * Used when user edits a collection entry in the UI to correct values.
 *
 * Key behaviors:
 * - Updates collection document with edited values (metersIn, metersOut, prevIn, prevOut, notes, etc.)
 * - Recalculates movement and SAS metrics when meters change
 * - Recalculates SAS time ranges when timestamp changes
 * - Updates machine collectionMetersHistory entry
 * - Does NOT update machine.collectionMeters (only creation flow does this)
 * - Calls updateRegularAndRamClearMeters with fully updated document
 *
 * @see updateMachineCollectionData — for CREATION flow (updates machine meters)
 *
 * @param {string} id - Required (path). The _id of the collection to update.
 *
 * Body fields:
 * @param {number} [metersIn] - Optional. New meter-in reading. Triggers movement
 *                                            recalculation and cascade.
 * @param {number} [metersOut] - Optional. New meter-out reading. Triggers movement
 *                                            recalculation and cascade.
 * @param {string|Date} [sasEndTime] - Optional. Override for sasMeters.sasEndTime.
 * @param {string|Date} [sasStartTime] - Optional. Override for sasMeters.sasStartTime.
 * @param {string|Date} [timestamp] - Optional. Collection timestamp.
 * @param {string|Date} [collectionTime] - Optional. Alternative collection timestamp field.
 * @param {boolean} [ramClear] - Optional. Flags that a RAM-clear occurred.
 * @param {number} [ramClearMetersIn] - Optional. Post-RAM-clear meter-in value.
 * @param {number} [ramClearMetersOut] - Optional. Post-RAM-clear meter-out value.
 * @param {number} [ramClearCoinIn] - Optional. Post-RAM-clear coin-in value.
 * @param {number} [ramClearCoinOut] - Optional. Post-RAM-clear coin-out value.
 * @param {string} [notes] - Optional. Free-text notes on the collection entry.
 * @param {number} [prevIn] - Optional. Override for the previous meter-in value.
 * @param {number} [prevOut] - Optional. Override for the previous meter-out value.
 *
 * Note: collector and collectorName fields are intentionally stripped before the update
 * to prevent accidental reassignment of collection ownership.
 *
 * Flow:
 * 1. Parse route parameters and request body
 * 2. Validate collection ID
 * 3. Connect to database and fetch original collection
 * 4. Handle RAM clear toggle (relay-aware)
 * 5. Remove immutable _id, extract SAS time fields
 * 6. Build and apply first update (basic fields + explicit SAS times)
 * 7. Recalculate movement and SAS metrics if needed
 * 8. Update machine collectionMetersHistory
 * 9. Cascade recalculation to related collections
 * 10. Log activity and return updated collection
 */
export async function PATCH(request: NextRequest) {
  return withApiAuth(request, async () => {
    const startTime = Date.now();
    const functionName = 'PATCH /api/collection-reports/collections/[id]';
    const user = extractUserFromRequest(request);
    const { pathname } = request.nextUrl;
    const collectionId = pathname.split('/').pop();

    try {
      // ============================================================================
      // STEP 1: Parse request body
      // ============================================================================
      const updateData = await request.json();

      // ============================================================================
      // STEP 2: Validate collection ID
      // ============================================================================
      if (!collectionId) {
        logRouteError(
          functionName,
          'PATCH',
          '/api/collection-reports/collections/[id]',
          'Collection ID is required',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Collection ID is required' },
          { status: 400 }
        );
      }

      // ============================================================================
      // STEP 3: Fetch original collection (DB connection handled by withApiAuth)
      // ============================================================================
      const originalCollection = await Collections.findOne({
        _id: collectionId,
      }).lean<CollectionDocument | null>();

      if (!originalCollection) {
        return NextResponse.json(
          { success: false, error: 'Collection not found' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 3.5: Verify the user may access the collection's location
      // ============================================================================
      const hasAccess = await checkUserLocationAccess(
        String(originalCollection.location || '')
      );
      if (!hasAccess) {
        logRouteError(
          functionName,
          'PATCH',
          '/api/collection-reports/collections/[id]',
          'Unauthorized: Access denied',
          user
        );
        return NextResponse.json(
          { success: false, error: 'Unauthorized: Access denied' },
          { status: 403 }
        );
      }

      // ============================================================================
      // STEP 4: Handle RAM clear toggle (relay-aware)
      // ============================================================================
      const explicitSasEndTime = updateData.sasEndTime;
      const { unsetData } = await handleRamClearToggleWithRelayGuard(
        originalCollection,
        updateData,
        explicitSasEndTime
      );

      // ============================================================================
      // STEP 5: Remove immutable _id, extract SAS time fields, determine flags
      // ============================================================================
      const { _id, ...safeUpdateData } = updateData as Record<string, unknown>;
      if ('_id' in updateData) {
        console.warn('⚠️ API: Removed _id field from update data');
      }

      const sasFields = extractSasTimeFieldsFromPayload(safeUpdateData);
      const flags = determineRecalculationFlags(updateData, sasFields);

      // ============================================================================
      // STEP 6: Build and apply first update (basic fields + explicit SAS times)
      // ============================================================================
      const updatePayload: Record<string, unknown> = {
        ...safeUpdateData,
        updatedAt: new Date(),
      };

      if (sasFields.hasPayloadSasEndTime) {
        updatePayload['sasMeters.sasEndTime'] = new Date(
          sasFields.payloadSasEndTime as Date
        );
      }
      if (sasFields.hasPayloadSasStartTime) {
        updatePayload['sasMeters.sasStartTime'] = new Date(
          sasFields.payloadSasStartTime as Date
        );
      }

      const updateQuery: Record<string, unknown> = {
        $set: updatePayload,
      };
      if (Object.keys(unsetData).length > 0) {
        updateQuery.$unset = unsetData;
      }

      const updatedCollection = await Collections.findOneAndUpdate(
        { _id: collectionId },
        updateQuery,
        { new: true, runValidators: false }
      );

      if (!updatedCollection) {
        return NextResponse.json(
          { success: false, error: 'Collection not found' },
          { status: 404 }
        );
      }

      // ============================================================================
      // STEP 7: Recalculate movement and SAS metrics if needed
      // ============================================================================
      if (flags.shouldRecalculate || flags.needsSasTimeRecalculation) {
        try {
          const finalUpdatedCollection =
            await recalculateMovementAndSasForPatch(
              collectionId,
              updatedCollection,
              updateData,
              sasFields,
              flags
            );

          // ========================================================================
          // STEP 8: Update machine collectionMetersHistory
          // ========================================================================
          await updateMachineHistoryForPatch(updatedCollection, updateData);

          // ========================================================================
          // STEP 9: Cascade recalculation to related collections
          // ========================================================================
          await cascadeRecalculationForPatch(
            updatedCollection,
            flags.shouldRecalculate
          );

          // ========================================================================
          // STEP 10: Log activity and return
          // ========================================================================
          await logCollectionPatchActivity(
            request,
            updatedCollection,
            originalCollection as unknown as Record<string, unknown> | null,
            updateData,
            finalUpdatedCollection,
            collectionId
          );

          const duration = Date.now() - startTime;
          logRouteUpdate(
            functionName,
            'PATCH',
            '/api/collection-reports/collections/[id]',
            1,
            user,
            duration
          );

          return NextResponse.json({
            success: true,
            data: finalUpdatedCollection,
          });
        } catch (recalculationError) {
          console.error(
            '[PATCH /api/collection-reports/collections/[id]] Recalculation error:',
            recalculationError instanceof Error
              ? recalculationError.message
              : 'Unknown error'
          );
          return NextResponse.json({
            success: true,
            data: updatedCollection,
            warning: 'Recalculation failed, but basic update succeeded',
          });
        }
      }

      // No recalculation needed - return the updated collection
      const duration = Date.now() - startTime;
      logRouteUpdate(
        functionName,
        'PATCH',
        '/api/collection-reports/collections/[id]',
        1,
        user,
        duration
      );

      return NextResponse.json({
        success: true,
        data: updatedCollection,
      });
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : 'Internal server error';
      logRouteError(
        functionName,
        'PATCH',
        '/api/collection-reports/collections/[id]',
        errorMessage,
        user
      );
      console.error(
        '[PATCH /api/collection-reports/collections/[id]] Error:',
        error instanceof Error ? error.message : 'Unknown error'
      );
      return NextResponse.json(
        {
          success: false,
          error: 'Internal server error',
          details: error instanceof Error ? error.message : 'Unknown error',
        },
        { status: 500 }
      );
    }
  });
}

/**
 * CollectionReportFilters Component
 *
 * A robust horizontally-oriented filtering bar for narrowing down collection report lists.
 *
 * Features:
 * - Multi-criteria search (Location names, Report IDs, Serial numbers)
 * - Type-specific filtering (Manual reports vs Scheduled tasks)
 * - Date range selection with custom calendar integration
 * - Real-time "Clear All" capability for reset
 * - Responsive layout: Inline for desktop, stacked for mobile
 * - Informative "No Results" state handling
 * - Location selection dropdown
 * - Search functionality
 * - Uncollected only filter checkbox
 * - Status filters
 * - Clear filters button
 * - GSAP animations for search state
 * - Responsive design
 *
 * @param searchTerm - Active search string for text-based matching
 * @param searchType - Specific field toggle for the search input
 * @param dateRange - Standardized {from, to} date object for temporal filtering
 * @param onSearchChange - Callback for search text updates
 * @param onSearchTypeChange - Callback for switching search categories
 * @param onDateRangeChange - Callback for range selection updates
 * @param onClearFilters - Callback to reset all filter state
 * @param locations - Available locations list
 * @param selectedLocation - Currently selected location
 * @param onLocationChange - Callback when location changes
 * @param search - Current search value
 * @param onSearchChange - Callback when search changes
 * @param onSearchSubmit - Callback when search is submitted
 * @param showUncollectedOnly - Whether to show only uncollected reports
 * @param onShowUncollectedOnlyChange - Callback when uncollected filter changes
 * @param selectedFilters - Currently selected status filters
 * @param onFilterChange - Callback when filter changes
 * @param onClearFilters - Callback to clear all filters
 * @param isSearching - Whether search is in progress
 */
'use client';

import { useRef, useEffect } from 'react';
import { Checkbox } from '@/components/shared/ui/checkbox';
import { Button } from '@/components/shared/ui/button';
import LocationMultiSelect from '@/components/shared/ui/common/LocationMultiSelect';
import UnifiedSearchBar from '@/components/shared/ui/common/UnifiedSearchBar';

import { gsap } from 'gsap';
import type { CollectionReportFiltersProps } from '@/lib/types/components';

export default function CollectionReportFilters({
  locations,
  selectedLocation,
  onLocationChange,
  search,
  onSearchChange,
  searchType,
  onSearchTypeChange,
  onSearchSubmit,
  showUncollectedOnly,
  onShowUncollectedOnlyChange,
  selectedFilters,
  onFilterChange,
  onClearFilters,
  isSearching,
}: CollectionReportFiltersProps) {
  console.warn('[COLLECTION REPORT FILTERS] Component rendered with:');
  console.warn(`  - selectedLocation: "${selectedLocation}"`);
  console.warn(`  - locations count: ${locations.length}`);
  console.warn(`  - search: "${search}"`);
  console.warn(`  - showUncollectedOnly: ${showUncollectedOnly}`);

  // ============================================================================
  // State & Hooks
  // ============================================================================
  const filterRef = useRef<HTMLDivElement>(null);
  const selectRef = useRef<HTMLSelectElement>(null);
  const checkboxRef = useRef<HTMLDivElement>(null);

  // ============================================================================
  // Effects
  // ============================================================================
  // Search animation
  useEffect(() => {
    if (isSearching && filterRef.current) {
      gsap.fromTo(
        filterRef.current,
        { backgroundColor: '#6a11cb' },
        {
          backgroundColor: '#5119e9',
          duration: 0.5,
          ease: 'power2.out',
        }
      );
    }
  }, [isSearching]);

  // Location select animation
  useEffect(() => {
    if (selectRef.current) {
      gsap.fromTo(
        selectRef.current,
        { scale: 0.95 },
        {
          scale: 1,
          duration: 0.3,
          ease: 'back.out(1.7)',
        }
      );
    }
  }, [selectedLocation]);

  // Checkbox animation
  useEffect(() => {
    if (checkboxRef.current) {
      gsap.fromTo(
        checkboxRef.current,
        { scale: 0.9 },
        {
          scale: 1,
          duration: 0.3,
          ease: 'back.out(1.7)',
        }
      );
    }
  }, [showUncollectedOnly]);

  // ============================================================================
  // Render
  // ============================================================================
  return (
    <div
      ref={filterRef}
      className="flex w-full flex-col gap-y-3 rounded-lg bg-buttonActive p-4 lg:gap-y-4"
    >
      {/* Top row - Search and Location (md: side by side, lg: with Clear Button) */}
      <div className="flex flex-col gap-y-3 md:flex-row md:items-center md:gap-3 lg:gap-4">
        {/* Unified Search Bar */}
        <div className="min-w-0 flex-1 md:max-w-[400px] lg:w-[320px] lg:min-w-[280px] lg:flex-none">
          <UnifiedSearchBar
            searchType={searchType}
            onSearchTypeChange={onSearchTypeChange}
            searchValue={search}
            onSearchChange={onSearchChange}
            onSearchSubmit={onSearchSubmit}
            searchOptions={[
              { value: 'collector', label: 'Collector' },
              { value: 'location', label: 'Location' },
              { value: 'locationReportId', label: 'Report ID' },
              { value: 'locationId', label: 'Location ID' },
              { value: 'collectorId', label: 'Collector ID' },
            ]}
            isSearching={isSearching}
          />
        </div>

        {/* Location Select Dropdown */}
        <LocationMultiSelect
          locations={locations.map(loc => ({
            id: loc._id,
            name: loc.name,
            sasEnabled: false,
          }))}
          selectedLocations={
            Array.isArray(selectedLocation)
              ? selectedLocation
              : selectedLocation === 'all'
                ? []
                : [selectedLocation]
          }
          onSelectionChange={value => {
            onLocationChange(value.length === 0 ? 'all' : value);
          }}
          placeholder="Select Locations"
          className="w-full md:max-w-[300px] md:flex-1 lg:w-[240px] lg:min-w-[200px] lg:flex-none"
        />

        {/* Clear Filters Button - only visible on lg and above */}
        <div className="hidden items-center gap-4 lg:flex">
          <Button
            variant="outline"
            onClick={onClearFilters}
            className="whitespace-nowrap border-gray-300 bg-white text-gray-700 hover:bg-gray-50 hover:text-gray-900"
          >
            Clear Filters
          </Button>

          {/* Uncollected Only Checkbox - positioned to the right of Clear Filters on lg and above */}
          <div ref={checkboxRef} className="flex items-center">
            <label className="flex cursor-pointer items-center gap-2 font-medium text-white">
              <Checkbox
                id="uncollected-only"
                checked={showUncollectedOnly}
                onCheckedChange={checked =>
                  onShowUncollectedOnlyChange(!!checked)
                }
                className="border border-white bg-white data-[state=checked]:border-white data-[state=checked]:bg-buttonActive"
              />
              <span className="whitespace-nowrap text-sm font-medium">
                SHOW UNCOLLECTED ONLY
              </span>
            </label>
          </div>
        </div>
      </div>

      {/* Bottom row - Checkboxes and Clear Button (for mobile and tablet) */}
      <div className="flex flex-col gap-y-3 lg:hidden">
        {/* Uncollected Only + View Archived Checkboxes - only visible on mobile and tablet */}
        <div className="flex flex-wrap items-center gap-x-6 gap-y-3">
          <div ref={checkboxRef} className="flex items-center">
            <label className="flex cursor-pointer items-center gap-2 font-medium text-white">
              <Checkbox
                id="uncollected-only-mobile"
                checked={showUncollectedOnly}
                onCheckedChange={checked =>
                  onShowUncollectedOnlyChange(!!checked)
                }
                className="border border-white bg-white data-[state=checked]:border-white data-[state=checked]:bg-buttonActive"
              />
              <span className="whitespace-nowrap text-sm font-medium">
                SHOW UNCOLLECTED ONLY
              </span>
            </label>
          </div>

          {/* SMIB Filter Checkboxes - Better layout for md screens */}
          <div className="flex flex-col gap-3 sm:flex-row sm:flex-wrap sm:items-center">
            <div className="flex items-center space-x-2">
              <Checkbox
                id="smibFilter"
                checked={selectedFilters.includes('SMIBLocationsOnly')}
                onCheckedChange={checked =>
                  onFilterChange('SMIBLocationsOnly', !!checked)
                }
                className="border border-white bg-white data-[state=checked]:border-white data-[state=checked]:bg-buttonActive"
              />
              <label
                htmlFor="smibFilter"
                className="cursor-pointer whitespace-nowrap text-sm font-medium text-white"
              >
                SMIB
              </label>
            </div>

            <div className="flex items-center space-x-2">
              <Checkbox
                id="noSmibFilter"
                checked={selectedFilters.includes('NoSMIBLocation')}
                onCheckedChange={checked =>
                  onFilterChange('NoSMIBLocation', !!checked)
                }
                className="border border-white bg-white data-[state=checked]:border-white data-[state=checked]:bg-buttonActive"
              />
              <label
                htmlFor="noSmibFilter"
                className="cursor-pointer whitespace-nowrap text-sm font-medium text-white"
              >
                No SMIB
              </label>
            </div>

            <div className="flex items-center space-x-2">
              <Checkbox
                id="localServerFilter"
                checked={selectedFilters.includes('LocalServersOnly')}
                onCheckedChange={checked =>
                  onFilterChange('LocalServersOnly', !!checked)
                }
                className="border border-white bg-white data-[state=checked]:border-white data-[state=checked]:bg-buttonActive"
              />
              <label
                htmlFor="localServerFilter"
                className="cursor-pointer whitespace-nowrap text-sm font-medium text-white"
              >
                Local Server
              </label>
            </div>

            {/* Clear Filters Button - Better positioning on md */}
            <div className="flex w-full items-center sm:ml-auto sm:w-auto">
              <Button
                variant="outline"
                onClick={onClearFilters}
                className="w-full whitespace-nowrap border-gray-300 bg-white text-gray-700 hover:bg-gray-50 hover:text-gray-900 sm:w-auto"
              >
                Clear Filters
              </Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

/**
 * Collection Report List Operations Helper Functions
 *
 * Provides helper functions for collection report list/creation operations,
 * including chronological validation, location-based filtering, and sub-query handlers.
 *
 * @module app/api/lib/helpers/collectionReport/reportListOperations
 */

import { Collections } from '@/app/api/lib/models/collections';
import { GamingLocations } from '@/app/api/lib/models/gaminglocations';
import { fetchLocationsWithMachines } from '@/app/api/lib/helpers/collectionReport/queries';
import { logRouteError } from '@/app/api/lib/utils/routeLogger';
import type { CreateCollectionReportPayload } from '@/lib/types/api';
import type { CollectionReportRow } from '@/lib/types/components';
import type { CollectionDocument, GamingLocationDocument } from '@shared/types';
import { NextResponse } from 'next/server';

type RouteUser =
  | {
      _id: string;
      emailAddress?: string;
      firstName?: string;
      lastName?: string;
      username?: string;
    }
  | null
  | undefined;

/**
 * Validates machine collections for chronological ordering.
 * Skips machines that have BOTH a previous and next collection (middle-date insert).
 * Returns filtered valid machines and a flag indicating if this is the first report.
 */
export async function filterMachinesByChronologicalOrder(
  machines: CreateCollectionReportPayload['machines'],
  targetTime: Date
): Promise<{
  validMachines: NonNullable<CreateCollectionReportPayload['machines']>;
  isInsertingFirstReport: boolean;
}> {
  if (!machines || !Array.isArray(machines)) {
    return { validMachines: [], isInsertingFirstReport: false };
  }

  const validMachines: NonNullable<CreateCollectionReportPayload['machines']> =
    [];
  let firstReportInsertedCount = 0;

  for (const machine of machines) {
    if (!machine.machineId) continue;

    const nextReport = await Collections.findOne({
      machineId: machine.machineId,
      timestamp: { $gt: targetTime },
      deletedAt: { $exists: false },
    }).lean<CollectionDocument>();

    const prevReport = await Collections.findOne({
      machineId: machine.machineId,
      timestamp: { $lt: targetTime },
      deletedAt: { $exists: false },
    }).lean<CollectionDocument>();

    if (nextReport && prevReport) {
      console.warn(
        `[filterMachinesByChronologicalOrder] Chronological check failed for machine ${machine.machineId}: cannot insert a middle-date collection.`
      );
      continue;
    }

    validMachines.push(machine);

    if (nextReport && !prevReport) {
      firstReportInsertedCount++;
    }
  }

  return {
    validMachines,
    isInsertingFirstReport: firstReportInsertedCount > 0,
  };
}

/**
 * Filters collection reports by allowed location names.
 * Collection reports store location NAME in the location field, not ID.
 */
export async function filterReportsByAllowedLocationNames(
  reports: CollectionReportRow[],
  allowedLocationIds: string[]
): Promise<{ filteredReports: CollectionReportRow[]; error?: string }> {
  if (!Array.isArray(reports)) {
    return { filteredReports: [] };
  }

  const locations = await GamingLocations.find(
    { _id: { $in: allowedLocationIds } },
    { _id: 1, name: 1 }
  )
    .lean<GamingLocationDocument[]>()
    .exec();

  const allowedLocationNames = locations.map(loc => String(loc.name));

  if (!Array.isArray(allowedLocationNames)) {
    console.error(
      '[filterReportsByAllowedLocationNames] Failed to fetch location names'
    );
    return { filteredReports: [], error: 'Failed to fetch location names' };
  }

  const filteredReports = reports.filter(report => {
    const reportLocationName = String(report.location);
    return allowedLocationNames.includes(reportLocationName);
  });

  return { filteredReports };
}

/**
 * Handles the locationsWithMachines sub-query for the GET handler.
 * Returns { response } if this is a locationsWithMachines request, or null to continue normal flow.
 */
export async function handleLocationsWithMachinesRequest(
  searchParams: URLSearchParams,
  user: RouteUser,
  startTime: number,
  functionName: string
): Promise<{ response: NextResponse } | null> {
  if (!searchParams.get('locationsWithMachines')) return null;

  try {
    const rawLicenceeParam = searchParams.get('licencee') || undefined;
    const includeMachines = searchParams.get('includeMachines') === 'true';

    const result = await fetchLocationsWithMachines(
      rawLicenceeParam,
      includeMachines
    );
    if (
      !result ||
      (result.locations &&
        Array.isArray(result.locations) &&
        result.locations.length === 0)
    ) {
      console.warn(
        '[Collection Reports GET] No locations found or fetch failed'
      );
    }
    return { response: NextResponse.json(result) };
  } catch (error: unknown) {
    const duration = Date.now() - startTime;
    const errorMessage =
      error instanceof Error ? error.message : 'Unknown error';
    if (errorMessage === 'Unauthorized') {
      logRouteError(
        functionName,
        'GET',
        '/api/collection-reports',
        'Unauthorized',
        user ?? undefined
      );
      return {
        response: NextResponse.json({ error: 'Unauthorized' }, { status: 401 }),
      };
    }
    logRouteError(
      functionName,
      'GET',
      '/api/collection-reports',
      errorMessage,
      user ?? undefined
    );
    console.error(
      `[Collection Reports GET API] Error fetching locations with machines after ${duration}ms:`,
      errorMessage
    );
    return {
      response: NextResponse.json(
        {
          error: 'Failed to fetch locations with machines',
          details: errorMessage,
        },
        { status: 500 }
      ),
    };
  }
}

